I thought of something like this:

```python
class DjangoNowTest(SimpleTestCase):
    @staticmethod
    def _now(tz=None):
        return datetime.datetime(2015, 7, 8, 10, 33, 25, tzinfo=tz)

    def setUp(self):
        patcher = mock.patch('jdj_tags.extensions.datetime')
        dt_mock = patcher.start()
        dt_mock.now.configure_mock(side_effect=self._now)
        self.addCleanup(patcher.stop)

        self.env = Environment(extensions=[DjangoNow])

    def test_simple(self):
        template = self.env.from_string("{% now 'Y' %}")
        expected = self._now().strftime('%Y')

        self.assertEqual(expected, template.render())

    def test_as_var(self):
        template = self.env.from_string(
            "{% now 'Y' as cur_year %}Current year is: {{ cur_year }}!"
        )
        expected = "Current year is: %s!" % self._now().strftime('%Y')

        self.assertEqual(expected, template.render())
```

A cleaner way to work with an Option while still returning early might be:
```
let beginning_root = 
  if let Some(beginning_root) = self.gen_root_entry(subject_type, product_type) {
    beginning_root
  } else {
    return ...
  };
```

e.g.:
```
methods: {
    wrappedStartTracking() {
        this.startTracking(this.Kolibri);
    },
    wrappedUpdateProgress(progress) {
        this.updatedProgress(this.Kolibri, progress);
    },
}
```
